// Ads and their scheduled dates — keep in sync with ads.config.mjs / the July calendar.
const ADS = [
  { id: 'PlatformShowcase', voice: 'Christopher', audioOut: 'showcase-vo.mp3', scheduledDate: '2026-07-08',
    text: "Your next opportunity is already out there. It's just scattered — across funder portals, emails, spreadsheets, and relationships. Anansi Atlas maps the web of opportunity around your mission: funders, partners, government pathways, resources, and readiness. Your Opportunity Web Snapshot shows your strongest asset, your biggest gap, and the single highest-leverage move to make next. Anansi Atlas. Apply for a founding seat at anansi atlas dot com, slash anansi atlas." },
  { id: 'PilotSignup', voice: 'Jackson', audioOut: 'pilot-vo.mp3', scheduledDate: '2026-07-16',
    text: "Applications are open for the Founding Atlas Partners Pilot. We're selecting nineteen nonprofit and mission-driven organizations. Each partner receives a guided Opportunity Web Snapshot, a forty-five minute walkthrough, and the living platform. A hundred and fifty dollars a month, locked for life, for the first twenty organizations. Nineteen seats remain. Apply now at anansi atlas dot com, slash anansi atlas." }
];
const today = ($env.ADS_DATE_OVERRIDE || new Date().toISOString().slice(0,10));
const due = ADS.filter(a => a.scheduledDate === today);
return due.map(a => ({ json: { ...a, today } }));

// Resolve the voice id by NAME (auto-pull) and carry the ad forward.
const ad = $('Due ads today').item.json;
const voices = $json.voices || [];
const match = voices.find(v => (v.name || '').trim().toLowerCase() === ad.voice.trim().toLowerCase());
if (!match) { throw new Error(`Voice "${ad.voice}" not found in ElevenLabs account`); }
return [{ json: { id: ad.id, audioOut: ad.audioOut, text: ad.text, voiceId: match.voice_id } }];
